import React, { useState, useEffect } from 'react';
import api from '../../../services/api';
import FlightCard from '../FlightCard';
import AddFlightForm from './AddFlightForm';
import FlightStats from './FlightStats';
import AddScheduleModal from './AddScheduleModal';

const AdminFlightList = () => {
  const [flights, setFlights] = useState([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState('');
  const [showForm, setShowForm] = useState(false);
  const [editFlight, setEditFlight] = useState(null);
  const [showStats, setShowStats] = useState(false);
  const [deleteMsg, setDeleteMsg] = useState('');
  const [scheduleFlight, setScheduleFlight] = useState(null);

  const fetchFlights = async () => {
    setLoading(true);
    try {
      const res = await api.get('/flights');
      setFlights(res.data.data || []);
    } catch {
      setError('Failed to load flights.');
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => {
    fetchFlights();
  }, []);

  const handleAdd = () => {
    setEditFlight(null);
    setShowForm(true);
  };

  const handleEdit = (flight) => {
    setEditFlight(flight);
    setShowForm(true);
  };

  const handleAddSchedule = (flight) => {
    setScheduleFlight(flight);
  };

  const handleDelete = async (flight_id) => {
    if (!window.confirm('Delete this flight? This cannot be undone.')) return;
    try {
      await api.delete(`/flights/${flight_id}`);
      setDeleteMsg('Flight deleted.');
      fetchFlights();
      setTimeout(() => setDeleteMsg(''), 3000);
    } catch (err) {
      const msg = err.response?.data?.message || 'Delete failed.';
      setError(msg);
    }
  };

  const handleFormSuccess = () => {
    setShowForm(false);
    setEditFlight(null);
    fetchFlights();
  };

  return (
    <div className="page-container">
      <div className="page-header">
        <div>
          <h1>Flight Management</h1>
          <p>Manage all flights in the system</p>
        </div>
        <div className="header-actions">
          <button
            className="btn-secondary"
            onClick={() => setShowStats(!showStats)}
          >
            {showStats ? 'Hide Stats' : '📊 View Stats'}
          </button>
          <button className="btn-primary" onClick={handleAdd}>
            + Add Flight
          </button>
        </div>
      </div>

      {showStats && <FlightStats />}

      {error && <div className="alert alert-error">{error}</div>}
      {deleteMsg && <div className="alert alert-success">{deleteMsg}</div>}

      {loading ? (
        <div className="loading">Loading flights...</div>
      ) : (
        <>
          <div className="results-count">{flights.length} Flight{flights.length !== 1 ? 's' : ''}</div>
          {flights.length === 0 ? (
            <div className="empty-state">
              No flights yet. Click "Add Flight" to create one.
            </div>
          ) : (
            <div className="flights-grid">
              {flights.map((flight) => (
                <FlightCard
                  key={flight.flight_id}
                  flight={flight}
                  isAdmin={true}
                  onEdit={handleEdit}
                  onDelete={handleDelete}
                  onAddSchedule={handleAddSchedule}
                />
              ))}
            </div>
          )}
        </>
      )}

      {showForm && (
        <AddFlightForm
          editFlight={editFlight}
          onSuccess={handleFormSuccess}
          onCancel={() => { setShowForm(false); setEditFlight(null); }}
        />
      )}

      {scheduleFlight && (
        <AddScheduleModal
          flight={scheduleFlight}
          onSuccess={() => { setScheduleFlight(null); setDeleteMsg('Schedule created successfully!'); setTimeout(() => setDeleteMsg(''), 3000); }}
          onCancel={() => setScheduleFlight(null)}
        />
      )}
    </div>
  );
};

export default AdminFlightList;
